import{_ as n,O as t,H as e,f as p,k as i,i as l}from"./chunks/framework.Pt2pSV98.js";const m=JSON.parse('{"title":"用 AI 做翻译","description":"学会用 AI 做高质量多语言翻译——从基础翻译到术语管理，再到翻译审校","frontmatter":{"title":"用 AI 做翻译","description":"学会用 AI 做高质量多语言翻译——从基础翻译到术语管理，再到翻译审校","difficulty":"beginner"},"headers":[],"relativePath":"practices/ai-translation.md","filePath":"practices/ai-translation.md"}'),o={name:"practices/ai-translation.md"};function r(c,a,d,h,u,b){const s=t("DifficultyBadge");return e(),p("div",null,[i(s,{level:"beginner"}),a[0]||(a[0]=l(`<h1 id="用-ai-做翻译" tabindex="-1">用 AI 做翻译 <a class="header-anchor" href="#用-ai-做翻译" aria-label="Permalink to &quot;用 AI 做翻译&quot;">​</a></h1><p>翻译不再是逐词查词典——用 AI，你可以轻松完成多语言、专业领域的高质量翻译。本篇教你从&quot;随便翻翻&quot;到&quot;专业翻译&quot;的完整流程。</p><h2 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h2><ul><li>一个可用的 AI 对话工具（ChatGPT、Claude、DeepSeek 均可）</li><li>一篇需要翻译的文本（可以是文章、邮件、产品介绍等）</li></ul><hr><h2 id="第-1-步-基础翻译" tabindex="-1">第 1 步：基础翻译 <a class="header-anchor" href="#第-1-步-基础翻译" aria-label="Permalink to &quot;第 1 步：基础翻译&quot;">​</a></h2><p>最直接的用法：把需要翻译的内容贴给 AI，让它直接翻。</p><h3 id="示例-prompt" tabindex="-1">示例 Prompt <a class="header-anchor" href="#示例-prompt" aria-label="Permalink to &quot;示例 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请把下面这段中文翻译成英文：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&quot;近年来，人工智能技术发展迅猛，已经渗透到医疗、教育、金融等各个行业。</span></span>
<span class="line"><span>它不仅改变了我们的工作方式，也在重塑整个社会的运行模式。&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要求：</span></span>
<span class="line"><span>- 翻译准确，不要遗漏信息</span></span>
<span class="line"><span>- 英文表达自然流畅</span></span></code></pre></div><p>AI 会给出流畅的英文译文。如果觉得某个词或句子不够好，直接追问：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;reshaping&quot;这个词感觉不太对，有没有更自然的表达？</span></span></code></pre></div><h3 id="技巧" tabindex="-1">技巧 <a class="header-anchor" href="#技巧" aria-label="Permalink to &quot;技巧&quot;">​</a></h3><ul><li>先说源语言和目标语言</li><li>对译文风格有要求就直接提出来</li><li>不满意就追问，AI 不会嫌你烦</li></ul><hr><h2 id="第-2-步-指定风格和领域" tabindex="-1">第 2 步：指定风格和领域 <a class="header-anchor" href="#第-2-步-指定风格和领域" aria-label="Permalink to &quot;第 2 步：指定风格和领域&quot;">​</a></h2><p>同样的内容，在不同场景下翻译方式完全不同。告诉 AI 你的使用场景，它会自动调整措辞和语气。</p><h3 id="示例-prompt-1" tabindex="-1">示例 Prompt <a class="header-anchor" href="#示例-prompt-1" aria-label="Permalink to &quot;示例 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请把下面这段产品介绍翻译成英文，用于公司官网。</span></span>
<span class="line"><span>风格要求：专业、简洁、有说服力，适合面向海外客户。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[粘贴产品介绍文本]</span></span></code></pre></div><p>不同领域的翻译风格对比：</p><table tabindex="0"><thead><tr><th>领域</th><th>Prompt 关键描述</th><th>译文特点</th></tr></thead><tbody><tr><td>商务邮件</td><td>&quot;正式得体、礼貌清晰&quot;</td><td>敬语、完整句式</td></tr><tr><td>技术文档</td><td>&quot;准确优先、术语一致、简洁&quot;</td><td>短句、无歧义</td></tr><tr><td>文学作品</td><td>&quot;保留原文的美感和文学性&quot;</td><td>修辞、韵律</td></tr></tbody></table><hr><h2 id="第-3-步-保持术语一致性" tabindex="-1">第 3 步：保持术语一致性 <a class="header-anchor" href="#第-3-步-保持术语一致性" aria-label="Permalink to &quot;第 3 步：保持术语一致性&quot;">​</a></h2><p>长篇翻译最大的挑战是术语统一。比如 &quot;用户&quot; 到底翻译成 <code>user</code> 还是 <code>customer</code>？先让 AI 学一下你的术语表。</p><h3 id="示例-prompt-2" tabindex="-1">示例 Prompt <a class="header-anchor" href="#示例-prompt-2" aria-label="Permalink to &quot;示例 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我正在翻译一份产品文档，以下是术语对照表，请记住并在后续翻译中严格使用：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- 用户 → user（不是 customer）</span></span>
<span class="line"><span>- 账号 → account</span></span>
<span class="line"><span>- 登录 → sign in（不是 log in）</span></span>
<span class="line"><span>- 注册 → sign up</span></span>
<span class="line"><span>- 密码 → password</span></span>
<span class="line"><span>- 验证 → verify</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请确认你已经记住了这些术语。</span></span></code></pre></div><p>AI 确认后，再开始逐段翻译，它会严格遵守你的术语表。如果发现术语不一致，随时纠正：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这里用了 &quot;log in&quot;，请改成 &quot;sign in&quot;。</span></span>
<span class="line"><span>请把之后所有的 &quot;log in&quot; 都替换为 &quot;sign in&quot;。</span></span></code></pre></div><hr><h2 id="第-4-步-翻译审校" tabindex="-1">第 4 步：翻译审校 <a class="header-anchor" href="#第-4-步-翻译审校" aria-label="Permalink to &quot;第 4 步：翻译审校&quot;">​</a></h2><p>好翻译是改出来的。让 AI 自己检查自己的翻译，往往能发现很多问题。</p><h3 id="自我检查-prompt" tabindex="-1">自我检查 Prompt <a class="header-anchor" href="#自我检查-prompt" aria-label="Permalink to &quot;自我检查 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请逐条检查上述英文翻译，从以下维度分析：</span></span>
<span class="line"><span>1. 是否有语法错误？</span></span>
<span class="line"><span>2. 是否有信息遗漏或增添？</span></span>
<span class="line"><span>3. 表达是否地道自然？</span></span>
<span class="line"><span>4. 术语是否与之前保持一致？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>对每条问题，请给出修改建议。</span></span></code></pre></div><h3 id="修改-prompt" tabindex="-1">修改 Prompt <a class="header-anchor" href="#修改-prompt" aria-label="Permalink to &quot;修改 Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>根据你上面的检查结果，请重新翻译一遍，把发现的问题全部修正。</span></span></code></pre></div><p>如果需要更严格的审校，可以让 AI 用&quot;回译法&quot;——把英文再翻回中文，和原文对照：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请把你翻译的英文再翻回中文，让我和原文对照检查有没有信息偏差。</span></span></code></pre></div><hr><h2 id="关键技巧总结" tabindex="-1">关键技巧总结 <a class="header-anchor" href="#关键技巧总结" aria-label="Permalink to &quot;关键技巧总结&quot;">​</a></h2><ol><li><strong>给上下文</strong>：告诉 AI 这段翻译用在什么场景（官网 / 邮件 / 论文 / 社交媒体）</li><li><strong>定风格</strong>：明确说明语气（正式 / 轻松 / 专业 / 文艺）</li><li><strong>术语管理</strong>：先建术语表，让 AI 记住，全文统一</li><li><strong>迭代审校</strong>：让 AI 自查 + 修正，不要一次就过</li></ol><hr><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/tools/chatgpt.html">ChatGPT 工具详解</a></li><li><a href="/ai-knowledge/prompts/principles.html">清晰的 Prompt 怎么写</a></li><li><a href="/ai-knowledge/practices/chatgpt-coding.html">用 AI 辅助编程</a></li></ul>`,42))])}const q=n(o,[["render",r]]);export{m as __pageData,q as default};
